// MODUŁ 2 – DRZEWO LOKALIZACJI I MASZYNY\n// =============================================================\n\nmodel Location {\n  id       String       @id @default(uuid())\n  name     String\n  type     LocationType\n  parentId String?      @map(\"parent_id\")\n\n  parent   Location?  @relation(\"LocationTree\", fields: [parentId], references: [id])\n  children Location[] @relation(\"LocationTree\")\n  machines Machine[]\n\n  @@index([parentId])\n  @@map(\"locations\")\n}\n\nenum LocationType {\n  PLANT // zakład\n  HALL // hala\n  LINE // linia produkcyjna\n  STATION // stanowisko\n}\n\nmodel Machine {\n  id             String   @id @default(uuid())\n  name           String\n  serialNumber   String   @unique @map(\"serial_number\")\n  locationId     String   @map(\"location_id\")\n  operatingHours Float    @default(0) @map(\"operating_hours\")\n  purchaseDate   DateTime @map(\"purchase_date\")\n  purchasePrice  Decimal  @map(\"purchase_price\") @db.Decimal(10, 2)\n  isActive       Boolean  @default(true) @map(\"is_active\")\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n  updatedAt      DateTime @updatedAt @map(\"updated_at\")\n\n  location        Location          @relation(fields: [locationId], references: [id])\n  documents       MachineDocument[]\n  workOrders      WorkOrder[]\n  preventivePlans PreventivePlan[]\n\n  @@index([locationId])\n  @@map(\"machines\")\n}\n\nmodel MachineDocument {\n  id           String   @id @default(uuid())\n  machineId    String   @map(\"machine_id\")\n  uploadedById String   @map(\"uploaded_by_id\")\n  filename     String\n  filePath     String   @map(\"file_path\")\n  version      Int      @default(1)\n  isLatest     Boolean  @default(true) @map(\"is_latest\")\n  uploadedAt   DateTime @default(now()) @map(\"uploaded_at\")\n\n  machine    Machine @relation(fields: [machineId], references: [id], onDelete: Cascade)\n  uploadedBy User    @relation(fields: [uploadedById], references: [id])\n\n  @@index([machineId])